const { useState, useEffect, useRef, useCallback } = React;

// ==================== STORAGE (Firebase + localStorage hibrit) ====================
const S = {
  // Kaydet: önce localStorage (anlık), sonra Firebase (arka planda)
  save: (k, v) => {
    // 1. Hızlı yerel kayıt
    try {
      localStorage.setItem('rep_'+k, JSON.stringify(v));
    } catch(e) {
      try {
        const pruneKeys = ['globalChat','cityChats','casinoLogs','activityLog','historyLog','liveFeed','liveNews','socialPosts','newspapers','randomEvents','scandals','netWorthHistory'];
        pruneKeys.forEach(dk=>{ try{localStorage.removeItem('rep_'+dk);}catch(x){} });
        localStorage.setItem('rep_'+k, JSON.stringify(v));
      } catch(e2) {
        try {
          const truncated = Array.isArray(v) ? v.slice(0,10) : v;
          localStorage.setItem('rep_'+k, JSON.stringify(truncated));
        } catch(e3) {}
      }
    }
    // 2. Sunucudan gelen güncellemeyse döngüyü önle: Firebase'e geri yazma
    if (window._fbServerSyncedKeys && window._fbServerSyncedKeys.has(k)) {
      window._fbServerSyncedKeys.delete(k); // tek seferlik - sil ve çık
      return;
    }
    // 3. Firebase kuyruğuna ekle (büyük loglar hariç sık sync)
    if (window._logKeys && window._logKeys.includes(k)) {
      // Log verileri 30 sn'de bir sync (bant genişliği tasarrufu)
      window._fbPendingWrites[k] = v;
      if (!window._fbLogTimer) {
        window._fbLogTimer = setTimeout(() => {
          window._fbLogTimer = null;
          window._fbScheduleFlush && window._fbScheduleFlush();
        }, 30000);
      }
    } else {
      window._fbPendingWrites[k] = v;
      window._fbScheduleFlush && window._fbScheduleFlush(k);
    }
  },
  // Yükle: localStorage'dan (senkron, React init için gerekli)
  load: (k, d) => { try { const v = localStorage.getItem('rep_'+k); return v ? JSON.parse(v) : d; } catch(e) { return d; } }
};

// ==================== PARA FORMATLAMA ====================
// Miktara göre otomatik kısaltma: ₺1.5B, ₺2.3M, ₺850Mr, ₺1.2T
const fmtMoney = (v, prefix="₺") => {
  const n = Number(v) || 0;
  const abs = Math.abs(n);
  const sign = n < 0 ? "-" : "";
  if (abs >= 1e12)       return `${sign}${prefix}${(abs/1e12).toFixed(abs>=10e12?1:2).replace(/\.?0+$/,"")}T`;
  if (abs >= 1e9)        return `${sign}${prefix}${(abs/1e9).toFixed(abs>=10e9?1:2).replace(/\.?0+$/,"")}Mr`;
  if (abs >= 1e6)        return `${sign}${prefix}${(abs/1e6).toFixed(abs>=10e6?1:2).replace(/\.?0+$/,"")}M`;
  if (abs >= 1e3)        return `${sign}${prefix}${(abs/1e3).toFixed(abs>=10e3?0:1).replace(/\.?0+$/,"")}B`;
  return `${sign}${prefix}${abs.toFixed(0)}`;
};

// Firebase realtime güncellemelerini React state'e bağla
// (globalChat, cityChats vb. başka cihazdan gelince React'i bilgilendir)
window._fbSyncCallbacks = {};
window.addEventListener('fb-sync', (e) => {
  const { key, value } = e.detail;
  if (window._fbSyncCallbacks[key]) {
    window._fbSyncCallbacks[key](value);
  }
});

// ==================== ADMOB CALLBACK HANDLERS ====================
// Android'den çağrılır: window.onRewardEarned("daily_double")
window.onRewardEarned = function(rewardType) {
  if (rewardType === "daily_double") {
    window.dispatchEvent(new CustomEvent("admob-reward", { detail: { type: "daily_double" } }));
  }
};
// Android'den çağrılır: reklam yüklenemezse
window.onRewardFailed = function(rewardType) {
  window.dispatchEvent(new CustomEvent("admob-reward-failed", { detail: { type: rewardType } }));
};

// ==================== GANG/PARTY/FAMILY NORMALIZERS ====================
// Module-level (component dışında) — her zaman tanımlı, TDZ sorunu yok
const normalizeGang = (g) => {
  if (!g || typeof g !== 'object') return g;
  let members = g.members;
  if (!Array.isArray(members)) {
    // Eski veri: members sayı (memberCount) veya başka bir şey olabilir
    members = g.leader ? [g.leader] : [];
  }
  return {...g, members};
};
const normalizeMembers = (obj) => {
  if (!obj || typeof obj !== 'object') return obj;
  if (!Array.isArray(obj.members)) {
    return {...obj, members: obj.leader ? [obj.leader] : []};
  }
  return obj;
};

// Seçim verisini normalize et (userVotedIds ve votedBy her zaman array)
const normalizeElections = (raw) => {
  if (!raw || typeof raw !== 'object') return {};
  const out = {};
  Object.entries(raw).forEach(([k, v]) => {
    if (!v || typeof v !== 'object') { out[k] = v; return; }
    out[k] = {
      ...v,
      userVotedIds: Array.isArray(v.userVotedIds) ? v.userVotedIds : [],
      candidates: Array.isArray(v.candidates) ? v.candidates.map(c => ({
        ...c,
        votedBy: Array.isArray(c.votedBy) ? c.votedBy : [],
      })) : [],
    };
  });
  return out;
};

// CollabRequests normalize et
const normalizeCollabRequests = (arr) => {
  if (!Array.isArray(arr)) return [];
  return arr.filter(r => r && typeof r === 'object' && r.id && r.from && r.to);
};

