// ==================== LOCAL FILE MUSIC PLAYER ====================
// Singleton music state shared across instances
if (!window.__MUSIC_STATE) {
  window.__MUSIC_STATE = {
    playlist: [], currentIdx: 0, isPlaying: false,
    volume: 0.7, shuffle: false, repeat: false,
    listeners: new Set(),
    notify() { this.listeners.forEach(fn => fn({...this})); }
  };
}
if (!window.__MUSIC_AUDIO) {
  window.__MUSIC_AUDIO = new Audio();
  window.__MUSIC_AUDIO.preload = "metadata";
  const ms = window.__MUSIC_STATE;
  window.__MUSIC_AUDIO.addEventListener('ended', () => {
    if(ms.repeat){ window.__MUSIC_AUDIO.currentTime=0; window.__MUSIC_AUDIO.play(); }
    else if(ms.playlist.length>1){
      ms.currentIdx = ms.shuffle ? Math.floor(Math.random()*ms.playlist.length) : (ms.currentIdx+1)%ms.playlist.length;
      window.__MUSIC_AUDIO.src = ms.playlist[ms.currentIdx]?.url||"";
      window.__MUSIC_AUDIO.play().catch(()=>{});
      ms.notify();
    }
  });
}

function UrlMusicPlayer({ miniMode = false }) {
  const [state, setState] = React.useState({...(window.__MUSIC_STATE||{})});
  const [currentTime, setCurrentTime] = React.useState(0);
  const [duration, setDuration] = React.useState(0);
  const [isExpanded, setIsExpanded] = React.useState(false);
  const audio = window.__MUSIC_AUDIO;
  const ms = window.__MUSIC_STATE;

  // Ignore old ref-based approach, use singleton
  const audioRef = React.useRef(null);
  const playlist = state.playlist;
  const currentIdx = state.currentIdx;
  const isPlaying = state.isPlaying;
  const volume = state.volume;
  const shuffle = state.shuffle;
  const repeat = state.repeat;

  // Subscribe to state changes



  React.useEffect(() => {
    const handler = (newState) => setState({...newState});
    ms.listeners.add(handler);
    return () => ms.listeners.delete(handler);
  }, []);

  // Sync audio time
  React.useEffect(() => {
    const onTime = () => setCurrentTime(audio.currentTime);
    const onDur = () => setDuration(audio.duration||0);
    const onPlay = () => { ms.isPlaying=true; ms.notify(); };
    const onPause = () => { ms.isPlaying=false; ms.notify(); };
    audio.addEventListener('timeupdate', onTime);
    audio.addEventListener('durationchange', onDur);
    audio.addEventListener('play', onPlay);
    audio.addEventListener('pause', onPause);
    return () => {
      audio.removeEventListener('timeupdate', onTime);
      audio.removeEventListener('durationchange', onDur);
      audio.removeEventListener('play', onPlay);
      audio.removeEventListener('pause', onPause);
    };
  }, []);

  const setPlaylist = (fn) => {
    const newList = typeof fn==='function' ? fn(ms.playlist) : fn;
    ms.playlist = newList;
    ms.notify();
  };
  const setCurrentIdx = (i) => { ms.currentIdx=i; ms.notify(); };
  const setIsPlaying = (v) => { ms.isPlaying=v; ms.notify(); };
  const setVolume = (v) => { ms.volume=v; audio.volume=v; ms.notify(); };
  const setShuffle = (v) => { ms.shuffle=v; ms.notify(); };
  const setRepeat = (v) => { ms.repeat=v; ms.notify(); };

  const current = playlist[currentIdx] || null;

  // Sync audio src when track changes
  React.useEffect(() => {
    if (!current) return;
    if (audio.src !== current.url) {
      audio.src = current.url;
      audio.volume = ms.volume;
      if (ms.isPlaying) audio.play().catch(()=>{ms.isPlaying=false;ms.notify();});
    }
  }, [currentIdx, JSON.stringify(playlist.map(p=>p.url))]);

  React.useEffect(() => {
    audio.volume = volume;
  }, [volume]);

  const addFiles = (e) => {
    const files = Array.from(e.target.files || []);
    if (!files.length) return;
    const newTracks = files
      .filter(f => f.type.startsWith('audio/') || f.type.startsWith('video/'))
      .map(f => ({ name: f.name.replace(/\.[^.]+$/, ''), url: URL.createObjectURL(f) }));
    const newList = [...playlist, ...newTracks];
    setPlaylist(newList);
    if (ms.playlist.length === 0 && newTracks.length > 0) {
      ms.currentIdx = 0;
      audio.src = newTracks[0].url;
      audio.volume = ms.volume;
    }
    ms.playlist = newList;
    ms.notify();
    e.target.value = '';
  };

  const togglePlay = () => {
    const current2 = ms.playlist[ms.currentIdx];
    if (!current2) return;
    if (!audio.src || audio.src === window.location.href) {
      audio.src = current2.url;
      audio.volume = ms.volume;
    }
    if (ms.isPlaying) { audio.pause(); }
    else { audio.play().catch(()=>{}); }
  };

  const nextTrack = () => {
    if (!ms.playlist.length) return;
    const next = ms.shuffle ? Math.floor(Math.random()*ms.playlist.length) : (ms.currentIdx+1)%ms.playlist.length;
    ms.currentIdx = next;
    ms.isPlaying = true;
    ms.notify();
    audio.src = ms.playlist[next]?.url||"";
    audio.play().catch(()=>{});
  };

  const prevTrack = () => {
    if (!ms.playlist.length) return;
    const prev = (ms.currentIdx-1+ms.playlist.length)%ms.playlist.length;
    ms.currentIdx = prev;
    ms.isPlaying = true;
    ms.notify();
    audio.src = ms.playlist[prev]?.url||"";
    audio.play().catch(()=>{});
  };

  const seek = (e) => {
    const rect = e.currentTarget.getBoundingClientRect();
    const pct = (e.clientX - rect.left) / rect.width;
    audio.currentTime = pct * duration;
  };

  const fmt = (s) => {
    const m = Math.floor(s/60), sec = Math.floor(s%60);
    return `${m}:${sec<10?'0':''}${sec}`;
  };

  const removeTrack = (i) => {
    const newList = ms.playlist.filter((_,idx)=>idx!==i);
    if (i === ms.currentIdx && newList.length > 0) {
      ms.currentIdx = Math.min(i, newList.length-1);
      audio.src = newList[ms.currentIdx]?.url||"";
    } else if (newList.length === 0) {
      audio.pause(); audio.src = "";
      ms.currentIdx = 0; ms.isPlaying = false;
    }
    ms.playlist = newList;
    ms.notify();
  };

  // Sync to global so audio persists across page changes
  React.useEffect(() => {
    window.__musicPlayerRef = audioRef;
    window.__musicPlayerState = { isPlaying, currentIdx, playlist };
  });

  return (
    <div style={{width:"100%",maxWidth:420,marginBottom:"1rem",fontFamily:"Nunito,sans-serif"}}>
      {/* audio managed by window.__MUSIC_AUDIO singleton */}

      {/* Compact Player Bar */}
      <div style={{background:"rgba(10,10,10,0.9)",border:"1px solid rgba(0,201,255,0.18)",borderRadius:"0.75rem",overflow:"hidden"}}>
        {/* Track info + controls row */}
        <div style={{display:"flex",alignItems:"center",gap:"0.5rem",padding:"0.55rem 0.75rem"}}>
          {/* Play/Pause */}
          <button onClick={togglePlay} disabled={!current}
            style={{width:34,height:34,borderRadius:"50%",background:current?"#D00000":"rgba(0,201,255,0.15)",border:"none",color:"#fff",fontSize:"1rem",cursor:current?"pointer":"default",display:"flex",alignItems:"center",justifyContent:"center",flexShrink:0}}>
            {isPlaying?"⏸":"▶"}
          </button>
          {/* Track name */}
          <div style={{flex:1,minWidth:0}}>
            <div style={{fontSize:"0.78rem",fontWeight:700,color:current?"#F0F0F0":"#555",overflow:"hidden",textOverflow:"ellipsis",whiteSpace:"nowrap"}}>
              {current ? current.name : "Şarkı seçilmedi"}
            </div>
            {playlist.length > 0 && <div style={{fontSize:"0.62rem",color:"#666"}}>{currentIdx+1}/{playlist.length} • {fmt(currentTime)}/{fmt(duration)}</div>}
          </div>
          {/* Prev/Next */}
          <button onClick={prevTrack} disabled={!current} style={{background:"none",border:"none",color:current?"#aaa":"#444",cursor:current?"pointer":"default",fontSize:"0.9rem",padding:"0.1rem"}}>⏮</button>
          <button onClick={nextTrack} disabled={!current} style={{background:"none",border:"none",color:current?"#aaa":"#444",cursor:current?"pointer":"default",fontSize:"0.9rem",padding:"0.1rem"}}>⏭</button>
          {/* Expand toggle - only in full mode */}
          {!miniMode && <button onClick={()=>setIsExpanded(!isExpanded)} style={{background:"none",border:"none",color:"#555",cursor:"pointer",fontSize:"0.85rem",padding:"0.1rem"}}>{isExpanded?"▲":"▼"}</button>}
        </div>

        {/* Progress bar */}
        {current && (
          <div onClick={seek} style={{height:3,background:"rgba(255,255,255,0.06)",cursor:"pointer",marginBottom:0}}>
            <div style={{height:"100%",width:`${duration?((currentTime/duration)*100):0}%`,background:"#D00000",transition:"width 0.2s"}}/>
          </div>
        )}

        {/* Expanded controls - only in full mode */}
        {!miniMode && isExpanded && (
          <div style={{padding:"0.6rem 0.75rem",borderTop:"1px solid rgba(255,255,255,0.06)"}}>
            {/* Volume + Shuffle + Repeat */}
            <div style={{display:"flex",alignItems:"center",gap:"0.5rem",marginBottom:"0.6rem"}}>
              <span style={{fontSize:"0.72rem",color:"#777"}}>🔊</span>
              <input type="range" min="0" max="1" step="0.05" value={volume}
                onChange={e=>setVolume(parseFloat(e.target.value))}
                style={{flex:1,accentColor:"#D00000",height:3}} />
              <button onClick={()=>setShuffle(!shuffle)} style={{background:shuffle?"rgba(0,201,255,0.15)":"none",border:`1px solid ${shuffle?"rgba(208,0,0,0.5)":"rgba(255,255,255,0.1)"}`,borderRadius:"0.3rem",color:shuffle?"#FF6060":"#666",cursor:"pointer",fontSize:"0.7rem",padding:"0.15rem 0.4rem"}}>🔀</button>
              <button onClick={()=>setRepeat(!repeat)} style={{background:repeat?"rgba(0,201,255,0.15)":"none",border:`1px solid ${repeat?"rgba(208,0,0,0.5)":"rgba(255,255,255,0.1)"}`,borderRadius:"0.3rem",color:repeat?"#FF6060":"#666",cursor:"pointer",fontSize:"0.7rem",padding:"0.15rem 0.4rem"}}>🔁</button>
            </div>

            {/* Playlist */}
            {playlist.length > 0 && (
              <div style={{maxHeight:120,overflowY:"auto",marginBottom:"0.5rem"}}>
                {playlist.map((t,i)=>(
                  <div key={i} onClick={()=>{ms.currentIdx=i;ms.isPlaying=true;ms.notify();audio.src=ms.playlist[i]?.url||"";audio.play().catch(()=>{}); }}
                    style={{display:"flex",justifyContent:"space-between",alignItems:"center",padding:"0.25rem 0.4rem",borderRadius:"0.3rem",cursor:"pointer",background:i===currentIdx?"rgba(0,201,255,0.12)":"transparent",marginBottom:"0.1rem"}}>
                    <span style={{fontSize:"0.73rem",color:i===currentIdx?"#FF6060":"#bbb",overflow:"hidden",textOverflow:"ellipsis",whiteSpace:"nowrap",flex:1}}>{i===currentIdx&&isPlaying?"▶ ":""}{t.name}</span>
                    <button onClick={e=>{e.stopPropagation();removeTrack(i);}} style={{background:"none",border:"none",color:"#555",cursor:"pointer",fontSize:"0.7rem",flexShrink:0,marginLeft:"0.3rem"}}>✕</button>
                  </div>
                ))}
              </div>
            )}

            {/* File input */}
            <label style={{display:"flex",alignItems:"center",justifyContent:"center",gap:"0.4rem",background:"rgba(208,0,0,0.08)",border:"1px dashed rgba(208,0,0,0.35)",borderRadius:"0.5rem",padding:"0.4rem 0.75rem",color:"#ff6060",fontSize:"0.78rem",cursor:"pointer",fontWeight:600}}>
              <span>🎵</span> Cihazdan Müzik Ekle
              <input type="file" accept="audio/*,video/*" multiple onChange={addFiles} style={{display:"none"}} />
            </label>
            {playlist.length > 0 && (
              <button onClick={()=>{ms.playlist=[];ms.currentIdx=0;ms.isPlaying=false;ms.notify();audio.pause();audio.src="";}} style={{display:"block",margin:"0.4rem auto 0",background:"none",border:"none",color:"#555",cursor:"pointer",fontSize:"0.7rem"}}>🗑 Listeyi Temizle</button>
            )}
          </div>
        )}
      </div>
    </div>
  );
}


// ==================== NOTIFICATION ====================
function Notification({ msg, onClose }) {
  useEffect(() => { const t = setTimeout(onClose, 3500); return () => clearTimeout(t); }, []);
  if (!msg) return null;
  return (
    <div className="notification">
      {msg}
    </div>
  );
}

// ==================== BROADCAST BANNER ====================
const BROADCAST_TYPES = {
  system:   { icon:"📢", color:"#60A5FA", bg:"rgba(37,99,235,0.18)", border:"rgba(59,130,246,0.55)", label:"Sistem" },
  election: { icon:"🗳️", color:"#A78BFA", bg:"rgba(124,58,237,0.18)", border:"rgba(139,92,246,0.55)", label:"Seçim" },
  law:      { icon:"📜", color:"#34D399", bg:"rgba(16,185,129,0.15)", border:"rgba(16,185,129,0.5)",  label:"Yasa" },
  city:     { icon:"🏙️", color:"#FBBF24", bg:"rgba(245,158,11,0.15)", border:"rgba(245,158,11,0.5)",  label:"Şehir" },
  gang:     { icon:"⚔️", color:"#F87171", bg:"rgba(239,68,68,0.15)",  border:"rgba(239,68,68,0.5)",   label:"Çete" },
  warning:  { icon:"⚠️", color:"#FB923C", bg:"rgba(234,88,12,0.18)",  border:"rgba(234,88,12,0.55)",  label:"Uyarı" },
  gift:     { icon:"🎁", color:"#F472B6", bg:"rgba(236,72,153,0.15)", border:"rgba(236,72,153,0.5)",  label:"Hediye" },
};

function BroadcastBanner({ notif, onClose }) {
  const [prog, setProgress] = React.useState(100);
  const DURATION = 9000;
  useEffect(() => {
    if (!notif) return;
    const start = Date.now();
    const iv = setInterval(() => {
      const elapsed = Date.now() - start;
      const remaining = Math.max(0, 100 - (elapsed / DURATION) * 100);
      setProgress(remaining);
      if (remaining === 0) { clearInterval(iv); onClose(); }
    }, 80);
    return () => clearInterval(iv);
  }, [notif]);

  if (!notif) return null;
  const t = BROADCAST_TYPES[notif.type] || BROADCAST_TYPES.system;

  return (
    <div style={{
      position:"fixed", top:0, left:0, right:0, zIndex:99999,
      background:t.bg, borderBottom:`2px solid ${t.border}`,
      backdropFilter:"blur(18px)", WebkitBackdropFilter:"blur(18px)",
      padding:"0.75rem 1rem 0.55rem",
      animation:"slideDown 0.35s cubic-bezier(0.34,1.56,0.64,1)"
    }}>
      <style>{`@keyframes slideDown{from{transform:translateY(-100%);opacity:0}to{transform:translateY(0);opacity:1}}`}</style>
      <div style={{maxWidth:700,margin:"0 auto",display:"flex",alignItems:"flex-start",gap:"0.65rem"}}>
        <div style={{fontSize:"1.5rem",lineHeight:1,marginTop:"0.05rem",flexShrink:0}}>{t.icon}</div>
        <div style={{flex:1,minWidth:0}}>
          <div style={{display:"flex",alignItems:"center",gap:"0.5rem",marginBottom:"0.15rem"}}>
            <span style={{fontFamily:"Syne,sans-serif",fontWeight:800,color:t.color,fontSize:"0.72rem",
              textTransform:"uppercase",letterSpacing:"0.1em"}}>{t.label}</span>
            {notif.sender&&<span style={{fontSize:"0.65rem",color:"rgba(255,255,255,0.4)"}}>· {notif.sender}</span>}
            <span style={{fontSize:"0.62rem",color:"rgba(255,255,255,0.3)",marginLeft:"auto",flexShrink:0}}>
              {new Date(notif.ts||Date.now()).toLocaleTimeString("tr-TR",{hour:"2-digit",minute:"2-digit"})}
            </span>
          </div>
          {notif.title&&<div style={{fontWeight:700,color:"#fff",fontSize:"0.88rem",marginBottom:"0.15rem",fontFamily:"Syne,sans-serif"}}>{notif.title}</div>}
          <div style={{color:"rgba(255,255,255,0.82)",fontSize:"0.82rem",lineHeight:1.45,wordBreak:"break-word"}}>{notif.message}</div>
        </div>
        <button onClick={onClose} style={{
          background:"rgba(255,255,255,0.08)",border:"1px solid rgba(255,255,255,0.15)",
          borderRadius:7,color:"rgba(255,255,255,0.6)",cursor:"pointer",padding:"0.3rem 0.55rem",
          fontSize:"0.78rem",flexShrink:0,marginTop:"0.1rem",WebkitTapHighlightColor:"transparent"
        }}>✕</button>
      </div>
      {/* İlerleme çubuğu */}
      <div style={{position:"absolute",bottom:0,left:0,height:3,background:`linear-gradient(90deg,${t.color},${t.border})`,
        width:`${prog}%`,transition:"width 0.08s linear",borderRadius:"0 2px 0 0"}} />
    </div>
  );
}

// ===== TRANSMSG: Çeviri butonlu mesaj bileşeni =====
function TransMsg({ text, lang }) {
  const [translated, setTranslated] = React.useState(null);
  const [loading, setLoading] = React.useState(false);
  if (!text) return null;
  const needsTranslate = lang && lang !== "tr";
  const doTranslate = async () => {
    if (loading || translated) return;
    setLoading(true);
    try {
      const res = await fetch(`https://api.mymemory.translated.net/get?q=${encodeURIComponent(text.slice(0,500))}&langpair=tr|${lang}`);
      const data = await res.json();
      const t2 = data.responseData && data.responseData.translatedText;
      if (t2 && t2 !== text) setTranslated(t2);
      else setTranslated(text);
    } catch(e) { setTranslated(text); }
    setLoading(false);
  };
  return (
    <span>
      {translated || text}
      {needsTranslate && !translated && (
        <button onClick={doTranslate} disabled={loading}
          style={{background:"none",border:"none",color:"rgba(96,165,250,0.6)",cursor:"pointer",fontSize:"0.58rem",padding:"0 3px",fontFamily:"inherit",marginLeft:3}}>
          {loading ? "⏳" : "🌐"}
        </button>
      )}
    </span>
  );
}

