  const [elections, setElections] = useState(()=>{
    const raw = S.load("elections",{});
    // Bot adayları ve bot oylarını temizle + normalize
    const cleaned = {};
    Object.entries(raw).forEach(([key,el])=>{
      const cleanCandidates = (el.candidates||[]).filter(c=>!c.isBot && c.role!=="bot" && !(c.username||"").includes("[Bot]"));
      const cleanVotes = {};
      cleanCandidates.forEach(c=>{ cleanVotes[c.username] = (el.votes||{})[c.username]||0; });
      const cleanResults = (el.results||[]).filter(r=>!r.isBot && !(r.candidate||"").includes("[Bot]"));
      cleaned[key] = {
        ...el,
        candidates: cleanCandidates.map(c=>({...c, votedBy: Array.isArray(c.votedBy)?c.votedBy:[]})),
        votes: cleanVotes,
        results: cleanResults,
        userVotedIds: Array.isArray(el.userVotedIds) ? el.userVotedIds : [],
      };
    });
    return normalizeElections(cleaned);
  });
