  // ===== REFAH/KAYYUM =====
  React.useEffect(()=>{
    const DECAY_INTERVAL=3600000; // 1 saat
    const DECAY_AMOUNT=8; // Her saatte 8 refah düşer
    const COOLDOWN=6*3600000; // 6 saat
    const now=Date.now();
    const allCities=["İstanbul","Ankara","İzmir","Bursa","Adana","Antalya","Konya","Gaziantep","Mersin","Trabzon"];
    let changed=false;
    const updWelf={...cityWelfare};
    allCities.forEach(city=>{
      const lastBuild=cityBuildCooldown[city]||0;
      const timeSinceBuild=now-lastBuild;
      if(lastBuild>0&&timeSinceBuild>COOLDOWN){
        const decayPeriods=Math.floor((timeSinceBuild-COOLDOWN)/DECAY_INTERVAL);
        if(decayPeriods>0){
          const cur=(updWelf[city]&&updWelf[city].welfare!==undefined)?updWelf[city].welfare:75;
          const newVal=Math.max(0,cur-DECAY_AMOUNT*decayPeriods);
          if(newVal!==cur){updWelf[city]={...(updWelf[city]||{}),welfare:newVal};changed=true;}
        }
      }
    });
    if(changed){setCityWelfare(updWelf);S.save("cityWelfare",updWelf);}
  },[]);
