  // ==================== OTOMATİK EKONOMİ HABERLERİ ====================
  React.useEffect(()=>{
    const ECO_TEMPLATES = [
      // Enflasyon haberleri
      (e)=> e.inflation>70 ? `🆘 HİPERENFLASYON ALARMI: TÜFE %${e.inflation.toFixed(1)}'e Fırladı! Merkez Bankası Acil Toplantı Çağrısı` : null,
      (e)=> e.inflation>40 ? `⚠️ Enflasyon Kontrol Edilemiyor: TÜFE %${e.inflation.toFixed(1)} ile Yıllık Rekor Kırdı` : null,
      (e)=> e.inflation>20 ? `📊 TÜFE %${e.inflation.toFixed(1)}'de — Alım Gücü Eriyor, Asgari Ücret Talebi Yükseliyor` : null,
      (e)=> e.inflation<=10 && e.inflation>=0 ? `✅ Enflasyon Kontrol Altında: TÜFE %${e.inflation.toFixed(1)} — Ekonomide İstikrar Sinyali` : null,
      // Faiz haberleri
      (e)=> e.interestRate>25 ? `🏦 Merkez Bankası Faizi %${e.interestRate}'e Çekti — Kredi Piyasaları Felç, Yatırımcılar Kaçıyor` : null,
      (e)=> e.interestRate>15 ? `📈 Yüksek Faiz Tartışması: %${e.interestRate} Politika Faizi Büyümeyi Freniyor mu?` : null,
      (e)=> e.interestRate<5 ? `💸 Merkez Bankası Faizi %${e.interestRate}'e İndirdi — Konut Kredilerinde Patlama Bekleniyor` : null,
      // Hazine haberleri
      (e)=> (e.treasury||0)>50000000000 ? `💰 Devlet Hazinesi Güçlü: ${((e.treasury||0)/1e9).toFixed(1)} Milyar ₺ Rezerv — Bütçe Fazlası Açıklandı` : null,
      (e)=> (e.treasury||0)<1000000 ? `🚨 Hazine Boş! Devlet Borçlanmaya Gidiyor — IMF ile Görüşmeler Başladı` : null,
      (e)=> (e.treasury||0)<50000000 ? `⚠️ Bütçe Açığı Büyüyor: Hazine Gelirleri Giderleri Karşılamıyor` : null,
      // Vergi haberleri
      (e)=> e.taxRate>30 ? `😤 Vergi Yükü %${e.taxRate}'e Çıktı — Vatandaşlar İsyankar, Muhalefet Sert Eleştirdi` : null,
      (e)=> e.taxRate<5 ? `🎉 Vergi İndirimi: Oran %${e.taxRate}'e Düşürüldü — İş Dünyasından Alkış` : null,
      // Genel ekonomi haberleri
      ()=>`📉 Dolar/TL Kuru Günlük ${(Math.random()*2+0.5).toFixed(2)} Kuruş ${Math.random()>.5?'Yükseldi':'Düştü'} — Piyasalar Hareketli`,
      ()=>`🏭 Sanayi Üretim Endeksi ${Math.random()>.5?'Arttı':'Azaldı'}: ${(Math.random()*8+1).toFixed(1)}% ${Math.random()>.5?'Artış':'Düşüş'} ile Beklentilerin ${Math.random()>.5?'Üzerinde':'Altında'}`,
      ()=>`🌾 Tarım Ürünleri Fiyatları ${(Math.random()*15+5).toFixed(1)}% ${Math.random()>.5?'Yükseldi':'Düştü'} — Gıda Enflasyonu Gündemde`,
      ()=>`⚡ Enerji Fiyatları: Elektrik ve Doğalgaz Zamları ${Math.random()>.5?'Onaylandı':'İptal Edildi'}`,
      ()=>`🏠 Konut Fiyat Endeksi: Büyükşehirlerde ${(Math.random()*30+10).toFixed(1)}% Artış Kaydedildi`,
      ()=>`📦 İhracat Rakamları Açıklandı: Geçen Aya Göre ${(Math.random()*10+2).toFixed(1)}% ${Math.random()>.5?'Artış':'Düşüş'}`,
      ()=>`💼 İşsizlik Oranı: ${(Math.random()*8+8).toFixed(1)}% — Gençler Arasında Oran ${(Math.random()*15+15).toFixed(1)}%`,
      ()=>`🔄 Merkez Bankası Para Politikası Toplantısı: Faiz Kararı Beklentilerle ${Math.random()>.5?'Uyuştu':'Çelişti'}`,
      ()=>`📊 Borsa İstanbul: Bist100 ${Math.random()>.5?'Rekor':'Dip'} Gördü — Yatırımcılar ${Math.random()>.5?'Alım':'Satım'} Tarafında`,
      ()=>`🏦 Banka Kredi Faizleri Güncellendi: Tüketici Kredisi Oranları %${(Math.random()*20+25).toFixed(1)}'e ${Math.random()>.5?'Yükseldi':'Düştü'}`,
      ()=>`🌍 Türkiye Kredi Notu: Uluslararası Ajanslar Görünümü ${['Stabil','Negatif','Pozitif'][Math.floor(Math.random()*3)]} Olarak Belirledi`,
      ()=>`⛽ Akaryakıt Fiyatları: Benzin ${Math.random()>.5?'Zamlandı':'İndirildi'} — Motorin ${(Math.random()*5+3).toFixed(2)} Kuruş ${Math.random()>.5?'Arttı':'Düştü'}`,
    ];
    const generateEcoNews = () => {
      const e = JSON.parse(localStorage.getItem('rep_economy')||'{"inflation":5,"treasury":1000000,"taxRate":10,"interestRate":5}');
      const applicable = ECO_TEMPLATES.map(fn => { try{ return fn(e); }catch{return null;} }).filter(Boolean);
      if(!applicable.length) return;
      const headline = applicable[Math.floor(Math.random()*applicable.length)];
      const cats = ['Ekonomi','Piyasalar','Maliye'];
      const cat = cats[Math.floor(Math.random()*cats.length)];
      const now = new Date();
      const article = {
        id: `eco_${Date.now()}_${Math.random().toString(36).slice(2)}`,
        title: headline,
        content: `Bu haber UnderState Ekonomi Bülteni tarafından otomatik olarak oluşturulmuştur. Güncel ekonomi verileri ve piyasa göstergeleri analiz edilerek hazırlanmıştır. Daha detaylı bilgi için Maliye Bakanlığı açıklamalarını ve resmi bülteni takip ediniz.\n\n📅 ${now.toLocaleDateString('tr-TR')} · 🕐 ${now.toLocaleTimeString('tr-TR',{hour:'2-digit',minute:'2-digit'})}`,
        category: cat,
        author: '📊 Ekonomi Bülteni',
        date: now.toLocaleDateString('tr-TR'),
        likes: 0,
        views: Math.floor(Math.random()*500+100),
        isAuto: true,
        ts: Date.now(),
      };
      setNewspapers(prev => {
        const arr = Array.isArray(prev) ? prev : [];
        const recent = arr.filter(p=>p.isAuto && Date.now()-(p.ts||0)<300000);
        if(recent.length>=1) return arr;
        return [article, ...arr].slice(0,150);
      });
      try {
        window._pushNotif?.('📰 Ekonomi Bülteni', headline.slice(0,80), 'eco-news');
      } catch{}
    };
    generateEcoNews();
    const iv = setInterval(generateEcoNews, 5*60*1000);
    return () => clearInterval(iv);
  }, [economy.inflation, economy.interestRate, economy.taxRate, (economy.treasury||0) > 0]);

  // ==================== v4: OTOMATİK SİSTEM EFFECTLERİ ====================
