  // NPC AI Simülasyonu — 10 saniyede bir aktivite üret
  React.useEffect(()=>{
    const NPC_ACTIONS = {
      aggressive:  ["rakibine meydan okudu","saldırı başlattı","ittifakı bozdu","çete kurdu"],
      political:   ["yasa tasarısı sundu","miting düzenledi","oy topladı","kampanya başlattı"],
      economic:    ["holding açtı","hisse sattı","fabrika kurdu","ihracat anlaşması imzaladı"],
      criminal:    ["soygun düzenledi","kara para aklandı","bölge kapattı","silah depoladı"],
      academic:    ["ders verdi","araştırma tamamladı","öğrenci mezun etti","makale yazdı"],
      trader:      ["ticaret anlaşması kurdu","pazar açtı","fiyat belirledi","stok yeniledi"],
      farmer:      ["hasat yaptı","tarla suladi","mahsul sattı","yeni ekim yaptı"],
    };
    const interval = setInterval(()=>{
      const npc = NPC_DEFS[Math.floor(Math.random()*NPC_DEFS.length)];
      const actions = NPC_ACTIONS[npc.personality]||["aktivite gösterdi"];
      const action = actions[Math.floor(Math.random()*actions.length)];
      const newEntry = {
        id: Date.now(),
        npcId: npc.id,
        username: npc.username,
        city: npc.city,
        position: npc.position,
        avatar: npc.avatar,
        action,
        time: new Date().toLocaleTimeString("tr-TR"),
        ts: Date.now(),
      };
      setNpcActivity(prev=>{
        const upd = [newEntry,...(prev||[])].slice(0,50);
        S.save("npcActivity", upd);
        return upd;
      });
    }, 10000);
    return ()=>clearInterval(interval);
  }, []);

